	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

package registry

import (
	"fmt"
	"strings"
)

// PackageType represents the type of a registry package.
type PackageType string

const (
	PackageTypeWorkflow     PackageType = "workflow"
	PackageTypePlugin       PackageType = "plugin"
	PackageTypePersonaPack  PackageType = "persona-pack"
	PackageTypeTemplatePack PackageType = "template-pack"
	PackageTypeResource     PackageType = "resource"
)

// InstallMapping describes a source→target copy during installation.
type InstallMapping struct {
	Source string `yaml:"source"`
	Target string `yaml:"target"`
}

// PackageInstall describes what to copy during installation.
type PackageInstall struct {
	Root       *InstallMapping  `yaml:"root,omitempty"`       // plugin root (e.g., .ddx/plugins/helix)
	Skills     []InstallMapping `yaml:"skills,omitempty"`     // skills directories (copied to each target)
	Scripts    *InstallMapping  `yaml:"scripts,omitempty"`    // scripts/binaries
	Symlinks   []SymlinkMapping `yaml:"symlinks,omitempty"`   // post-install symlinks
	Executable []string         `yaml:"executable,omitempty"` // paths (relative to root) that must be executable
}

// SymlinkMapping describes a symlink to create during installation.
type SymlinkMapping struct {
	Source string `yaml:"source"` // the source path (relative to install root)
	Target string `yaml:"target"` // the target path (where symlink points)
}

// Package describes a single installable package.
type Package struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        PackageType    `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  string         `yaml:"api_version,omitempty"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords,omitempty"`
	// Extra captures top-level keys not recognized by this DDx version so
	// newer manifests can keep their unknown fields in memory without
	// silently dropping them. See SD-018 "Manifest Versioning". Not
	// marshaled via `yaml:"-"` so callers must preserve it explicitly.
	Extra map[string]any `yaml:"-"`
}

// Registry holds the list of known packages.
type Registry struct {
	Packages []Package
}

// BuiltinRegistry returns the built-in registry of known packages.
func BuiltinRegistry() *Registry {
	return &Registry{
		Packages: []Package{
			{
				Name:        "ddx",
				Version:     "0.4.7",
				Description: "DDx default library: prompts, personas, MCP configs, environments, skills",
				Type:        PackageTypePlugin,
				Source:      "https://github.com/DocumentDrivenDX/ddx",
				Install: PackageInstall{
					Root: &InstallMapping{
						Source: "library",
						Target: ".ddx/plugins/ddx",
					},
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
				},
				Keywords: []string{"library", "prompts", "personas", "mcp", "default", "skills"},
			},
			{
				Name:        "helix",
				Version:     "0.3.2",
				Description: "Supervisory autopilot for AI-assisted software delivery",
				Type:        PackageTypeWorkflow,
				Source:      "https://github.com/DocumentDrivenDX/helix",
				Install: PackageInstall{
					// Plugin installs are project-local (FEAT-015): the tree
					// lives under .ddx/plugins/<name>/, never in $HOME.
					Root: &InstallMapping{
						Source: ".",
						Target: ".ddx/plugins/helix",
					},
					// Skills installed to project-local skill directories.
					// skills.Install copies real files into both .agents/skills/
					// and .claude/skills/ regardless of mapping target.
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
					// CLI script → ~/.local/bin/helix
					// Uses scripts/helix directly (bin/helix has a symlink
					// resolution bug when invoked through a symlink).
					Scripts: &InstallMapping{
						Source: "scripts/helix",
						Target: "~/.local/bin/helix",
					},
					Executable: []string{
						"scripts/helix",
					},
				},
				Keywords: []string{"workflow", "methodology", "ai", "development"},
			},
		},
	}
}

// Find returns the package with the given name, or an error if not found.
func (r *Registry) Find(name string) (*Package, error) {
	for i := range r.Packages {
		if r.Packages[i].Name == name {
			return &r.Packages[i], nil
		}
	}
	return nil, fmt.Errorf("package %q not found in registry", name)
}

// Search returns all packages whose name, description, or keywords contain the query.
func (r *Registry) Search(query string) []Package {
	q := strings.ToLower(query)
	var results []Package
	for _, pkg := range r.Packages {
		if matchesQuery(pkg, q) {
			results = append(results, pkg)
		}
	}
	return results
}

func matchesQuery(pkg Package, query string) bool {
	if strings.Contains(strings.ToLower(pkg.Name), query) {
		return true
	}
	if strings.Contains(strings.ToLower(pkg.Description), query) {
		return true
	}
	if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
		return true
	}
	for _, kw := range pkg.Keywords {
		if strings.Contains(strings.ToLower(kw), query) {
			return true
		}
	}
	return false
}

// IsResourcePath returns true if name looks like a resource path (e.g. "persona/foo").
func IsResourcePath(name string) bool {
	return strings.Contains(name, "/")
}

package artifacttypes

import (
	"fmt"
	"os"
	"path"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"gopkg.in/yaml.v3"
)

// Loader discovers artifact types under an installed plugin root and caches
// the normalized result until the on-disk mtimes change.
type Loader struct {
	mu    sync.Mutex
	cache map[string]cacheEntry
}

type cacheEntry struct {
	index     *Index
	snapshots []snapshot
}

type snapshot struct {
	path    string
	exists  bool
	modTime time.Time
}

type metaDoc struct {
	Artifact struct {
		Name     string `yaml:"name"`
		ID       string `yaml:"id"`
		Type     string `yaml:"type"`
		Prefix   string `yaml:"prefix"`
		Phase    string `yaml:"phase"`
		Optional bool   `yaml:"optional"`
	} `yaml:"artifact"`
	Description string `yaml:"description"`
	Output      struct {
		Location string `yaml:"location"`
		Format   string `yaml:"format"`
		Naming   string `yaml:"naming"`
	} `yaml:"output"`
	Prompts struct {
		Generation string `yaml:"generation"`
		Review     string `yaml:"review"`
	} `yaml:"prompts"`
	Template struct {
		File string `yaml:"file"`
	} `yaml:"template"`
	Examples []struct {
		File        string `yaml:"file"`
		Description string `yaml:"description"`
	} `yaml:"examples"`
	IDFormat struct {
		Prefix      string `yaml:"prefix"`
		Pattern     string `yaml:"pattern"`
		Example     string `yaml:"example"`
		Description string `yaml:"description"`
	} `yaml:"id_format"`
	Name   string `yaml:"name"`
	ID     string `yaml:"id"`
	Prefix string `yaml:"prefix"`
	Phase  string `yaml:"phase"`
}

// NewLoader creates an empty loader with no cached roots.
func NewLoader() *Loader {
	return &Loader{cache: make(map[string]cacheEntry)}
}

// Load discovers artifact types for pluginRoot.
func (l *Loader) Load(pluginRoot string) (*Index, error) {
	if strings.TrimSpace(pluginRoot) == "" {
		return nil, fmt.Errorf("artifacttypes: plugin root is empty")
	}

	rootCanonical, err := canonicalPath(pluginRoot)
	if err != nil {
		return nil, err
	}

	l.mu.Lock()
	defer l.mu.Unlock()

	if entry, ok := l.cache[rootCanonical]; ok {
		if ok, err := entry.valid(); err == nil && ok {
			return entry.index.Clone(), nil
		}
	}

	pluginName, roots, snapshots, err := loadPluginRoots(rootCanonical)
	if err != nil {
		return nil, err
	}

	types, scannedSnapshots, err := scanPlugin(rootCanonical, pluginName, roots)
	if err != nil {
		return nil, err
	}

	snapshots = append(snapshots, scannedSnapshots...)
	index, err := buildIndex(types)
	if err != nil {
		return nil, err
	}
	l.cache[rootCanonical] = cacheEntry{index: index.Clone(), snapshots: snapshots}
	return index.Clone(), nil
}

func (e cacheEntry) valid() (bool, error) {
	for _, snap := range e.snapshots {
		info, err := os.Stat(snap.path)
		if err != nil {
			if os.IsNotExist(err) {
				return !snap.exists, nil
			}
			return false, err
		}
		if !snap.exists {
			return false, nil
		}
		if !info.ModTime().Equal(snap.modTime) {
			return false, nil
		}
	}
	return true, nil
}

func loadPluginRoots(rootCanonical string) (string, []string, []snapshot, error) {
	snapshots := []snapshot{recordSnapshot(rootCanonical)}
	manifest, _, err := registry.LoadPackageManifest(rootCanonical)
	if err != nil {
		if os.IsNotExist(err) {
			return filepath.Base(rootCanonical), []string{"workflows"}, snapshots, nil
		}
		// If the manifest parsed but had issues, still use the partial package
		// so artifact roots can be resolved from the preserved Extra map.
		if manifest == nil {
			return "", nil, snapshots, err
		}
	}
	if manifest == nil {
		return filepath.Base(rootCanonical), []string{"workflows"}, snapshots, nil
	}

	roots, err := artifactTypeRoots(manifest)
	if err != nil {
		return "", nil, snapshots, err
	}
	pluginName := strings.TrimSpace(manifest.Name)
	if pluginName == "" {
		pluginName = filepath.Base(rootCanonical)
	}
	snapshots = append(snapshots, recordSnapshot(filepath.Join(rootCanonical, "package.yaml")))
	return pluginName, roots, snapshots, nil
}

func artifactTypeRoots(pkg *registry.Package) ([]string, error) {
	if pkg == nil {
		return []string{"workflows"}, nil
	}
	extra, ok := pkg.Extra["artifact_type_roots"]
	if !ok {
		return []string{"workflows"}, nil
	}

	roots, err := stringsSlice(extra)
	if err != nil {
		return nil, fmt.Errorf("artifact_type_roots: %w", err)
	}
	if len(roots) == 0 {
		return []string{}, nil
	}
	return roots, nil
}

func stringsSlice(raw any) ([]string, error) {
	switch v := raw.(type) {
	case []string:
		return append([]string(nil), v...), nil
	case []any:
		out := make([]string, 0, len(v))
		for _, item := range v {
			s, ok := item.(string)
			if !ok {
				return nil, fmt.Errorf("expected string entries, got %T", item)
			}
			out = append(out, s)
		}
		return out, nil
	default:
		return nil, fmt.Errorf("expected list, got %T", raw)
	}
}

func scanPlugin(rootCanonical, pluginName string, patterns []string) ([]Type, []snapshot, error) {
	if len(patterns) == 0 {
		return []Type{}, []snapshot{recordSnapshot(rootCanonical)}, nil
	}

	concreteRoots, err := resolveRoots(rootCanonical, patterns)
	if err != nil {
		return nil, nil, err
	}

	var (
		types     []Type
		snapshots []snapshot
	)
	for _, root := range concreteRoots {
		snapshots = append(snapshots, recordSnapshot(root))
		err := filepath.WalkDir(root, func(p string, d os.DirEntry, walkErr error) error {
			if walkErr != nil {
				return walkErr
			}
			snapshots = append(snapshots, recordSnapshot(p))
			if !d.IsDir() {
				if filepath.Base(p) != "meta.yml" {
					return nil
				}
				typ, extraSnaps, err := parseTypeMeta(rootCanonical, pluginName, p)
				if err != nil {
					return err
				}
				types = append(types, typ)
				snapshots = append(snapshots, extraSnaps...)
			}
			return nil
		})
		if err != nil {
			return nil, nil, err
		}
	}
	return types, snapshots, nil
}

func parseTypeMeta(rootCanonical, pluginName, metaPath string) (Type, []snapshot, error) {
	metaCanonical, err := canonicalPath(metaPath)
	if err != nil {
		return Type{}, nil, err
	}
	if err := ensureWithinRoot(rootCanonical, metaCanonical); err != nil {
		return Type{}, nil, err
	}

	baseDir := filepath.Dir(metaCanonical)
	templatePath, err := resolveRelativeFile(rootCanonical, baseDir, "template.md")
	if err != nil {
		return Type{}, nil, fmt.Errorf("%s: template.md: %w", metaPath, err)
	}
	promptPath, err := resolveRelativeFile(rootCanonical, baseDir, "prompt.md")
	if err != nil {
		return Type{}, nil, fmt.Errorf("%s: prompt.md: %w", metaPath, err)

		return Type{}, nil, fmt.Errorf("%s: prompt.md: %w", metaPath, err)
	}

	raw, err := os.ReadFile(metaCanonical)
	if err != nil {
		return Type{}, nil, fmt.Errorf("read %s: %w", metaPath, err)
	}
	var doc metaDoc
	if err := yaml.Unmarshal(raw, &doc); err != nil {
		return Type{}, nil, fmt.Errorf("parse %s: %w", metaPath, err)
	}

	typeID := firstNonEmpty(doc.Artifact.ID, doc.ID, filepath.Base(baseDir))
	name := firstNonEmpty(doc.Artifact.Name, doc.Name, humanizeTypeID(typeID))
	pattern := firstNonEmpty(doc.Output.Naming, doc.IDFormat.Pattern, doc.Output.Location)
	prefix := firstNonEmpty(doc.Artifact.Prefix, doc.IDFormat.Prefix, doc.Prefix, inferPrefix(pattern), inferPrefixFromName(name), strings.ToUpper(typeID))
	phase := firstNonEmpty(doc.Artifact.Phase, doc.Phase, inferPhase(metaCanonical, rootCanonical))
	description := strings.TrimSpace(doc.Description)

	examples := make([]Example, 0, len(doc.Examples))
	if len(doc.Examples) > 0 {
		for _, ex := range doc.Examples {
			exPath, err := resolveRelativeFile(rootCanonical, baseDir, ex.File)
			if err != nil {
				return Type{}, nil, fmt.Errorf("%s: examples[%q]: %w", metaPath, ex.File, err)
			}
			rel, err := filepath.Rel(rootCanonical, exPath)
			if err != nil {
				return Type{}, nil, fmt.Errorf("%s: examples[%q]: %w", metaPath, ex.File, err)
			}
			examples = append(examples, Example{
				Path:        filepath.ToSlash(rel),
				Description: strings.TrimSpace(ex.Description),
			})
		}
	} else {
		examplePath, err := resolveRelativeFile(rootCanonical, baseDir, "example.md")
		if err == nil {
			rel, relErr := filepath.Rel(rootCanonical, examplePath)
			if relErr != nil {
				return Type{}, nil, relErr
			}
			examples = append(examples, Example{Path: filepath.ToSlash(rel)})
		}
	}

	metaRel, err := filepath.Rel(rootCanonical, metaCanonical)
	if err != nil {
		return Type{}, nil, err
	}
	templateRel, err := filepath.Rel(rootCanonical, templatePath)
	if err != nil {
		return Type{}, nil, err
	}
	promptRel, err := filepath.Rel(rootCanonical, promptPath)
	if err != nil {
		return Type{}, nil, err
	}

	typ := Type{
		Plugin:         pluginName,
		TypeID:         typeID,
		Name:           name,
		Description:    description,
		Prefix:         prefix,
		Pattern:        pattern,
		Phase:          phase,
		TemplatePath:   filepath.ToSlash(templateRel),
		PromptPath:     filepath.ToSlash(promptRel),
		Examples:       examples,
		SourceMetaPath: filepath.ToSlash(metaRel),
	}
	return typ, []snapshot{recordSnapshot(metaCanonical)}, nil
}

func resolveRoots(rootCanonical string, patterns []string) ([]string, error) {
	var roots []string
	for _, raw := range patterns {
		pattern := strings.TrimSpace(filepath.ToSlash(raw))
		if pattern == "" {
			continue
		}
		if err := validateRelativePattern(pattern); err != nil {
			return nil, err
		}
		if hasGlob(pattern) {
			matches, err := globDirs(rootCanonical, pattern)
			if err != nil {
				return nil, err
			}
			roots = append(roots, matches...)
			continue
		}
		candidate := filepath.Join(rootCanonical, filepath.FromSlash(pattern))
		canonical, err := canonicalPath(candidate)
		if err != nil {
			return nil, err
		}
		if err := ensureWithinRoot(rootCanonical, canonical); err != nil {
			return nil, err
		}
		info, err := os.Stat(canonical)
		if err != nil {
			if os.IsNotExist(err) {
				continue
			}
			return nil, err
		}
		if !info.IsDir() {
			continue
		}
		roots = append(roots, canonical)
	}
	roots = dedupeSortedPaths(roots)
	return roots, nil
}

func globDirs(rootCanonical, pattern string) ([]string, error) {
	var matches []string
	err := filepath.WalkDir(rootCanonical, func(p string, d os.DirEntry, walkErr error) error {
		if walkErr != nil {
			return walkErr
		}
		if !d.IsDir() {
			return nil
		}
		rel, err := filepath.Rel(rootCanonical, p)
		if err != nil {
			return err
		}
		rel = filepath.ToSlash(rel)
		if rel == "." {
			rel = ""
		}
		if matchGlobPath(pattern, rel) {
			matches = append(matches, p)
		}
		return nil
	})
	if err != nil {
		return nil, err
	}
	return dedupeSortedPaths(matches), nil
}

func dedupeSortedPaths(paths []string) []string {
	if len(paths) == 0 {
		return nil
	}
	sort.Strings(paths)
	out := paths[:0]
	var prev string
	for i, p := range paths {
		if i == 0 || p != prev {
			out = append(out, p)
			prev = p
		}
	}
	return append([]string(nil), out...)
}

func matchGlobPath(pattern, candidate string) bool {
	pp := splitPath(pattern)
	cp := splitPath(candidate)
	return matchGlobSegments(pp, cp)
}

func matchGlobSegments(pattern, candidate []string) bool {
	if len(pattern) == 0 {
		return len(candidate) == 0
	}
	if pattern[0] == "**" {
		if len(pattern) == 1 {
			return true
		}
		for i := 0; i <= len(candidate); i++ {
			if matchGlobSegments(pattern[1:], candidate[i:]) {
				return true
			}
		}
		return false
	}
	if len(candidate) == 0 {
		return false
	}
	ok, err := path.Match(pattern[0], candidate[0])
	if err != nil || !ok {
		return false
	}
	return matchGlobSegments(pattern[1:], candidate[1:])
}

func splitPath(s string) []string {
	parts := strings.Split(filepath.ToSlash(strings.TrimSpace(s)), "/")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		if part == "" || part == "." {
			continue
		}
		out = append(out, part)
	}
	return out
}

func validateRelativePattern(pattern string) error {
	if filepath.IsAbs(pattern) {
		return fmt.Errorf("artifact_type_roots: absolute paths are not allowed: %q", pattern)
	}
	for _, part := range splitPath(pattern) {
		if part == ".." {
			return fmt.Errorf("artifact_type_roots: path escapes plugin root: %q", pattern)
		}
	}
	return nil
}

func hasGlob(s string) bool {
	return strings.ContainsAny(s, "*?[")
}

func recordSnapshot(path string) snapshot {
	info, err := os.Stat(path)
	if err != nil {
		return snapshot{path: path}
	}
	return snapshot{path: path, exists: true, modTime: info.ModTime()}
}

func canonicalPath(path string) (string, error) {
	abs, err := filepath.Abs(path)
	if err != nil {
		return "", err
	}
	resolved, err := filepath.EvalSymlinks(abs)
	if err != nil {
		if os.IsNotExist(err) {
			return abs, nil
		}
		return "", err
	}
	return resolved, nil
}

func ensureWithinRoot(rootCanonical, candidateCanonical string) error {
	rel, err := filepath.Rel(rootCanonical, candidateCanonical)
	if err != nil {
		return err
	}
	if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return fmt.Errorf("path %s escapes plugin root %s", candidateCanonical, rootCanonical)
	}
	return nil
}

func resolveRelativeFile(rootCanonical, baseDir, rel string) (string, error) {
	trimmed := strings.TrimSpace(rel)
	if trimmed == "" {
		return "", fmt.Errorf("missing relative path")
	}
	if filepath.IsAbs(trimmed) {
		return "", fmt.Errorf("absolute paths are not allowed: %q", trimmed)
	}
	cleaned := filepath.Clean(filepath.FromSlash(trimmed))
	if cleaned == "." || cleaned == ".." || strings.HasPrefix(cleaned, ".."+string(filepath.Separator)) {
		return "", fmt.Errorf("path escapes type directory: %q", trimmed)
	}
	candidate := filepath.Join(baseDir, cleaned)
	info, err := os.Stat(candidate)
	if err != nil {
		return "", err
	}
	if info.IsDir() {
		return "", fmt.Errorf("%s is a directory", candidate)
	}
	canonical, err := canonicalPath(candidate)
	if err != nil {
		return "", err
	}
	if err := ensureWithinRoot(rootCanonical, canonical); err != nil {
		return "", err
	}
	return canonical, nil
}

func inferPhase(metaCanonical, rootCanonical string) string {
	rel, err := filepath.Rel(rootCanonical, metaCanonical)
	if err != nil {
		return ""
	}
	parts := splitPath(rel)
	for i := 0; i < len(parts); i++ {
		if parts[i] != "phases" || i+1 >= len(parts) {
			continue
		}
		phase := parts[i+1]
		if idx := strings.Index(phase, "-"); idx >= 0 && idx+1 < len(phase) {
			return phase[idx+1:]
		}
		return phase
	}
	return ""

package artifacttypes

import (
	"fmt"
	"sort"
	"strings"
	"unicode"
	"unicode/utf8"
)

// Example describes a worked example for an artifact type.
type Example struct {
	Path        string
	Description string
}

// Type is the normalized artifact-type record produced by the loader.
type Type struct {
	Plugin         string
	TypeID         string
	Name           string
	Description    string
	Prefix         string
	Pattern        string
	Phase          string
	TemplatePath   string
	PromptPath     string
	Examples       []Example
	SourceMetaPath string
}

// Index is the normalized in-memory lookup index for discovered artifact types.
type Index struct {
	Types    []Type
	byKey    map[string]int
	byPrefix map[string]int
	byPlugin map[string][]int
}

// Clone returns a deep copy of the index.
func (i *Index) Clone() *Index {
	if i == nil {
		return nil
	}
	clone := &Index{Types: make([]Type, len(i.Types))}
	for idx, typ := range i.Types {
		clone.Types[idx] = cloneType(typ)
	}
	clone.rebuildLookups()
	return clone
}

// ByPlugin returns all types belonging to plugin in deterministic order.
func (i *Index) ByPlugin(plugin string) []Type {
	if i == nil || len(i.Types) == 0 {
		return nil
	}
	idxs := i.byPlugin[plugin]
	if len(idxs) == 0 {
		return nil
	}
	out := make([]Type, 0, len(idxs))
	for _, idx := range idxs {
		out = append(out, cloneType(i.Types[idx]))
	}
	return out
}

// Lookup returns the type for a plugin/typeID pair.
func (i *Index) Lookup(plugin, typeID string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byKey[keyFor(plugin, typeID)]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

// LookupPrefix returns the first type that claims prefix.
func (i *Index) LookupPrefix(prefix string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byPrefix[prefix]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

func buildIndex(types []Type) (*Index, error) {
	sorted := make([]Type, len(types))
	copy(sorted, types)
	sort.Slice(sorted, func(i, j int) bool {
		if sorted[i].Plugin != sorted[j].Plugin {
			return sorted[i].Plugin < sorted[j].Plugin
		}
		if sorted[i].TypeID != sorted[j].TypeID {
			return sorted[i].TypeID < sorted[j].TypeID
		}
		return sorted[i].SourceMetaPath < sorted[j].SourceMetaPath
	})

	idx := &Index{
		Types:    sorted,
		byKey:    make(map[string]int, len(sorted)),
		byPrefix: make(map[string]int, len(sorted)),
		byPlugin: make(map[string][]int, len(sorted)),
	}

	for i, typ := range sorted {
		if typ.Plugin == "" {
			return nil, fmt.Errorf("artifact type %q missing plugin name", typ.TypeID)
		}
		if typ.TypeID == "" {
			return nil, fmt.Errorf("artifact type in plugin %q missing type id", typ.Plugin)
		}
		key := keyFor(typ.Plugin, typ.TypeID)
		if _, exists := idx.byKey[key]; exists {
			return nil, fmt.Errorf("duplicate artifact type %s/%s", typ.Plugin, typ.TypeID)
		}
		idx.byKey[key] = i
		idx.byPlugin[typ.Plugin] = append(idx.byPlugin[typ.Plugin], i)
		if typ.Prefix != "" {
			if _, exists := idx.byPrefix[typ.Prefix]; exists {
				return nil, fmt.Errorf("duplicate artifact type prefix %q", typ.Prefix)
			}
			idx.byPrefix[typ.Prefix] = i
		}
	}
	return idx, nil
}

func (i *Index) rebuildLookups() {
	i.byKey = make(map[string]int, len(i.Types))
	i.byPrefix = make(map[string]int, len(i.Types))
	i.byPlugin = make(map[string][]int, len(i.Types))
	for idx, typ := range i.Types {
		i.byKey[keyFor(typ.Plugin, typ.TypeID)] = idx
		i.byPlugin[typ.Plugin] = append(i.byPlugin[typ.Plugin], idx)
		if typ.Prefix != "" {
			i.byPrefix[typ.Prefix] = idx
		}
	}
}

func cloneType(typ Type) Type {
	clone := typ
	if len(typ.Examples) > 0 {
		clone.Examples = append([]Example(nil), typ.Examples...)
	}
	return clone
}

func keyFor(plugin, typeID string) string {
	return plugin + "\x00" + typeID
}

func humanizeTypeID(typeID string) string {
	if typeID == "" {
		return ""
	}
	fields := strings.FieldsFunc(typeID, func(r rune) bool {
		return r == '-' || r == '_' || r == '/'
	})
	if len(fields) == 0 {
		return titleWord(typeID)
	}
	for i, field := range fields {
		fields[i] = titleWord(field)
	}
	return strings.Join(fields, " ")
}

func titleWord(s string) string {
	if s == "" {
		return ""
	}
	r, size := utf8.DecodeRuneInString(s)
	return string(unicode.ToUpper(r)) + strings.ToLower(s[size:])
}

