 30	func artifactTypeDefinitionsForPath(workingDir, artifactPath string) ([]*ArtifactTypeDefinition, error) {
 31		prefix := prefixOf(artifactPath)
 32		if prefix == "" {
 33			return []*ArtifactTypeDefinition{}, nil
 34		}
 35		if workingDir == "" {
 36			return []*ArtifactTypeDefinition{}, nil
 37		}
 38	
 39		cfg, err := config.LoadWithWorkingDir(workingDir)
 40		if err != nil {
 41			return nil, fmt.Errorf("loading config: %w", err)
 42		}
 43		if cfg.Library == nil || strings.TrimSpace(cfg.Library.Path) == "" {
 44			return []*ArtifactTypeDefinition{}, nil
 45		}
 46	
 47		roots, err := artifactTypeRootsForLibraryPath(workingDir, cfg.Library.Path)
 48		if err != nil {
 49			return nil, err
 50		}
 51	
 52		seen := make(map[string]struct{})
 53		out := make([]*ArtifactTypeDefinition, 0)
 54		for _, root := range roots {
 55			index, err := artifactTypeLoader.Load(root)
 56			if err != nil {
 57				return nil, fmt.Errorf("loading artifact types from %s: %w", root, err)
 58			}
 59			for _, typ := range index.Types {
 60				if typ.Prefix != prefix {
 61					continue
 62				}
 63				key := typ.Plugin + "\x00" + typ.TypeID + "\x00" + typ.SourceMetaPath
 64				if _, ok := seen[key]; ok {
 65					continue
 66				}
 67				defn, err := buildArtifactTypeDefinition(root, typ)
 68				if err != nil {
 69					return nil, err
 70				}
 71				seen[key] = struct{}{}
 72				out = append(out, defn)
 73			}
 74		}
 75	
 76		sort.Slice(out, func(i, j int) bool {
 77			if out[i].Plugin != out[j].Plugin {
 78				return out[i].Plugin < out[j].Plugin
 79			}
 80			if out[i].TypeID != out[j].TypeID {
 81				return out[i].TypeID < out[j].TypeID
 82			}
 83			return out[i].SourceMetaPath < out[j].SourceMetaPath
 84		})
 85	
