110	func artifactTypeRootsForLibraryPath(workingDir, libraryPath string) ([]string, error) {
111		libPath := libraryPath
112		if !filepath.IsAbs(libPath) {
113			libPath = filepath.Join(workingDir, libPath)
114		}
115	
116		roots := []string{libPath}
117		parent := filepath.Dir(libPath)
118		if filepath.Base(parent) == "plugins" {
119			entries, err := os.ReadDir(parent)
120			if err != nil {
121				if os.IsNotExist(err) {
122					return []string{libPath}, nil
123				}
124				return nil, fmt.Errorf("reading plugin root directory %s: %w", parent, err)
125			}
126			for _, entry := range entries {
127				if entry.IsDir() {
128					roots = append(roots, filepath.Join(parent, entry.Name()))
129				}
130			}
131		}
132	
133		return dedupeArtifactTypeRoots(roots), nil
134	}
