136	func dedupeArtifactTypeRoots(roots []string) []string {
137		if len(roots) == 0 {
138			return nil
139		}
140		seen := make(map[string]struct{}, len(roots))
141		out := make([]string, 0, len(roots))
142		for _, root := range roots {
143			if root == "" {
144				continue
145			}
146			cleaned := filepath.Clean(root)
147			if _, ok := seen[cleaned]; ok {
148				continue
149			}
150			seen[cleaned] = struct{}{}
151			out = append(out, cleaned)
152		}
153		return out
