176	
177		return &ArtifactTypeDefinition{
178			Plugin:         typ.Plugin,
179			TypeID:         typ.TypeID,
180			Name:           typ.Name,
181			Description:    typ.Description,
182			Prefix:         typ.Prefix,
183			Pattern:        typ.Pattern,
184			Phase:          typ.Phase,
185			SourceMetaPath: typ.SourceMetaPath,
186			Template:       template,
187			Prompt:         prompt,
188			Examples:       examples,
189		}, nil
190	}
