192	func loadArtifactTypeDefinitionFile(root, relPath string, required bool) (*ArtifactTypeDefinitionFile, error) {
193		relPath = strings.TrimSpace(relPath)
194		if relPath == "" {
195			if required {
196				return nil, fmt.Errorf("missing file path")
197			}
198			return nil, nil
199		}
200	
201		absPath := filepath.Join(root, filepath.FromSlash(relPath))
202		content, truncated, originalBytes, err := evidence.ReadFileClamped(absPath, artifactTypeFileCapBytes)
203		if err != nil {
204			if required {
205				return nil, err
206			}
207			return nil, nil
208		}
209		inline := string(content)
210		return &ArtifactTypeDefinitionFile{
211			Path:        filepath.ToSlash(relPath),
212			Content:     inline,
213			IsTruncated: truncated,
214			SizeBytes:   int(originalBytes),
215		}, nil
216	}
217	
218	func loadArtifactTypeDefinitionExample(root string, ex artifacttypes.Example) (*ArtifactTypeDefinitionExample, error) {
219		file, err := loadArtifactTypeDefinitionFile(root, ex.Path, false)
220		if err != nil || file == nil {
221			return nil, err
222		}
223		desc := ex.Description
224		return &ArtifactTypeDefinitionExample{
225			Path:        file.Path,
226			Description: &desc,
227			Content:     file.Content,
228			IsTruncated: file.IsTruncated,
229			SizeBytes:   file.SizeBytes,
230		}, nil
231	}
