233	// prefixOf returns the first path segment, matching the frontend grouping helper.
234	func prefixOf(path string) string {
235		trimmed := strings.TrimSpace(filepath.ToSlash(path))
236		trimmed = strings.TrimPrefix(trimmed, "/")
237		if trimmed == "" {
238			return ""
239		}
240		if idx := strings.IndexByte(trimmed, '/'); idx >= 0 {
241			return trimmed[:idx]
242		}
243		return trimmed
244	}

