116	func TestTypeDefinitions_SingleMatch(t *testing.T) {
117		t.Setenv("HOME", t.TempDir())
118		workDir, store := setupIntegrationDir(t)
119		writeArtifactFixture(t, workDir, "DOC-001", "docs/helix/01-frame/single.md", "# single")
