121	
122		srv := httptest.NewServer(newArtifactGQLHandler(workDir, store))
123		defer srv.Close()
124	
125		projID := "proj-integration-" + filepath.Base(workDir)
126		out := fetchArtifactTypeDefinitions(t, srv, projID, "doc:DOC-001")
127		defs := out.Data.Artifact.TypeDefinitions
128		if len(defs) != 1 {
129			t.Fatalf("expected 1 artifact type definition, got %d", len(defs))
