136		}
137		if defs[0].Template.IsTruncated || defs[0].Prompt.IsTruncated {
138			t.Fatalf("expected untruncated small files, got template=%v prompt=%v", defs[0].Template.IsTruncated, defs[0].Prompt.IsTruncated)
139		}
140	}
